mapper.select:
SELECT h.id, DATE_FORMAT(h.record_date, '%Y-%m-%d') as recordDate, h.height, h.weight, h.temperature, h.health_status as healthStatus, h.diagnosis, h.operator_name as operatorName, h.remark, DATE_FORMAT(h.create_time, '%Y-%m-%d %H:%i:%s') as createTime, p.id as petId, p.name as petName, u.id as ownerId, u.username as ownerName, u.nickname as ownerNickname FROM pet_health_record h INNER JOIN pet_profile p ON h.pet_id = p.id LEFT JOIN user u ON p.user_id = u.id WHERE p.status = 1
AND (p.name LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY h.create_time DESC LIMIT #{offset}, #{limit}
